import{_ as i,o as e,c as l,ak as r}from"./chunks/framework.24mNDJkT.js";const p=JSON.parse('{"title":"一、IP 地址的定义","description":"","frontmatter":{},"headers":[],"relativePath":"计算机网络/网络层/认识 IP 地址.md","filePath":"计算机网络/网络层/认识 IP 地址.md","lastUpdated":1775305895000}'),t={name:"计算机网络/网络层/认识 IP 地址.md"};function h(d,a,n,s,o,c){return e(),l("div",null,[...a[0]||(a[0]=[r('<h1 id="一、ip-地址的定义" tabindex="-1">一、IP 地址的定义 <a class="header-anchor" href="#一、ip-地址的定义" aria-label="Permalink to “一、IP 地址的定义”">​</a></h1><p>IP 地址（Internet Protocol Address）是用于在因特网上<strong>唯一标识主机或路由器接口</strong>的逻辑地址。</p><h3 id="作用" tabindex="-1">作用 <a class="header-anchor" href="#作用" aria-label="Permalink to “作用”">​</a></h3><ul><li>标识网络中的设备（主机 / 路由器接口）</li><li>用于实现跨网络通信与寻址</li><li>支撑数据从源主机到目标主机的传输路径选择</li></ul><hr><h1 id="二、ip-地址-vs-mac-地址-核心对比" tabindex="-1">二、IP 地址 vs MAC 地址（核心对比） <a class="header-anchor" href="#二、ip-地址-vs-mac-地址-核心对比" aria-label="Permalink to “二、IP 地址 vs MAC 地址（核心对比）”">​</a></h1><table tabindex="0"><thead><tr><th>项目</th><th>IP 地址</th><th>MAC 地址</th></tr></thead><tbody><tr><td>层级</td><td>网络层</td><td>数据链路层</td></tr><tr><td>作用范围</td><td>跨网络通信（全网寻址）</td><td>局域网内通信</td></tr><tr><td>是否可变</td><td>可配置、可变化</td><td>固定（通常写入网卡）</td></tr><tr><td>功能</td><td>“导航作用”（路由选择）</td><td>“本地定位”（同一网络内找设备）</td></tr></tbody></table><hr><h2 id="通信过程理解-重点逻辑" tabindex="-1">通信过程理解（重点逻辑） <a class="header-anchor" href="#通信过程理解-重点逻辑" aria-label="Permalink to “通信过程理解（重点逻辑）”">​</a></h2><p>跨网络通信基本流程：</p><ol><li>源主机 → 通过 <strong>MAC 地址</strong> 找到本网络网关（路由器）</li><li>路由器 → 依据 <strong>IP 地址</strong> 进行跨网络转发（路由选择）</li><li>到达目标网络后 → 再用 <strong>MAC 地址</strong> 定位目标主机</li></ol><p>👉 结论：</p><ul><li>IP：负责“走哪条路”（路径选择）</li><li>MAC：负责“具体找谁”（局域网定位）</li></ul><hr><h1 id="三、ip-地址版本" tabindex="-1">三、IP 地址版本 <a class="header-anchor" href="#三、ip-地址版本" aria-label="Permalink to “三、IP 地址版本”">​</a></h1><h2 id="_1-ipv4" tabindex="-1">1. IPv4 <a class="header-anchor" href="#_1-ipv4" aria-label="Permalink to “1. IPv4”">​</a></h2><ul><li>长度：32 位（二进制）</li><li>表示能力：约 2³² ≈ 42 亿个地址</li><li>现实问题：地址资源不足（已接近耗尽）</li></ul><h3 id="ipv4-示例" tabindex="-1">IPv4 示例 <a class="header-anchor" href="#ipv4-示例" aria-label="Permalink to “IPv4 示例”">​</a></h3><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>11000000 10101000 00000001 00000001</span></span></code></pre></div><hr><h2 id="ipv4-地址表达方式" tabindex="-1">IPv4 地址表达方式 <a class="header-anchor" href="#ipv4-地址表达方式" aria-label="Permalink to “IPv4 地址表达方式”">​</a></h2><h3 id="点分十进制-标准表示法" tabindex="-1">点分十进制（标准表示法） <a class="header-anchor" href="#点分十进制-标准表示法" aria-label="Permalink to “点分十进制（标准表示法）”">​</a></h3><p>将 32 位分成 4 组，每组 8 位（二进制 → 十进制）：</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>192.168.1.1</span></span></code></pre></div><p>👉 优点：</p><ul><li>可读性强</li><li>易于记忆与配置</li></ul><hr><h2 id="_2-ipv6" tabindex="-1">2. IPv6 <a class="header-anchor" href="#_2-ipv6" aria-label="Permalink to “2. IPv6”">​</a></h2><ul><li>长度：128 位</li><li>地址数量：极其庞大（约 3×10³⁸）</li><li>目的：彻底解决 IPv4 地址不足问题</li></ul><p>👉 现实状态：</p><ul><li>IPv6 已存在，但 IPv4 仍是主流</li></ul><hr><h1 id="四、ip-地址结构-重点考点" tabindex="-1">四、IP 地址结构（重点考点） <a class="header-anchor" href="#四、ip-地址结构-重点考点" aria-label="Permalink to “四、IP 地址结构（重点考点）”">​</a></h1><p>IP 地址 = <strong>网络号 + 主机号</strong></p><hr><h2 id="_1-网络号-network-id" tabindex="-1">1. 网络号（Network ID） <a class="header-anchor" href="#_1-网络号-network-id" aria-label="Permalink to “1. 网络号（Network ID）”">​</a></h2><h3 id="作用-1" tabindex="-1">作用 <a class="header-anchor" href="#作用-1" aria-label="Permalink to “作用”">​</a></h3><ul><li>标识设备所在的网络（或网段）</li></ul><h3 id="判断同网段规则" tabindex="-1">判断同网段规则 <a class="header-anchor" href="#判断同网段规则" aria-label="Permalink to “判断同网段规则”">​</a></h3><p>👉 如果两个 IP 的网络号相同，则它们属于同一个网络</p><hr><h2 id="_2-主机号-host-id" tabindex="-1">2. 主机号（Host ID） <a class="header-anchor" href="#_2-主机号-host-id" aria-label="Permalink to “2. 主机号（Host ID）”">​</a></h2><h3 id="作用-2" tabindex="-1">作用 <a class="header-anchor" href="#作用-2" aria-label="Permalink to “作用”">​</a></h3><ul><li>标识同一网络内的具体设备</li></ul><h3 id="特点" tabindex="-1">特点 <a class="header-anchor" href="#特点" aria-label="Permalink to “特点”">​</a></h3><ul><li>同一网络内主机号必须唯一</li><li>不同网络之间可以重复</li></ul><hr><h2 id="类比理解" tabindex="-1">类比理解 <a class="header-anchor" href="#类比理解" aria-label="Permalink to “类比理解”">​</a></h2><ul><li>网络号 = 小区名称 / 楼栋号</li><li>主机号 = 门牌号</li></ul><p>👉 规则：</p><ul><li>同一小区不能有重复门牌号</li><li>不同小区可以重复门牌号（如 101）</li></ul><hr><h1 id="五、网络划分的本质" tabindex="-1">五、网络划分的本质 <a class="header-anchor" href="#五、网络划分的本质" aria-label="Permalink to “五、网络划分的本质”">​</a></h1><p>IP 地址通过“网络号 + 主机号”的划分，实现：</p><h3 id="_1-局域网-lan" tabindex="-1">1. 局域网（LAN） <a class="header-anchor" href="#_1-局域网-lan" aria-label="Permalink to “1. 局域网（LAN）”">​</a></h3><ul><li>同一网络号</li><li>设备直接通过 MAC 通信</li></ul><h3 id="_2-跨网络通信" tabindex="-1">2. 跨网络通信 <a class="header-anchor" href="#_2-跨网络通信" aria-label="Permalink to “2. 跨网络通信”">​</a></h3><ul><li>不同网络号</li><li>需要路由器转发</li></ul><h3 id="_3-互联网-internet" tabindex="-1">3. 互联网（Internet） <a class="header-anchor" href="#_3-互联网-internet" aria-label="Permalink to “3. 互联网（Internet）”">​</a></h3><ul><li>由大量局域网通过路由器互联构成</li></ul><hr><h1 id="六、关键理解总结-非常重要" tabindex="-1">六、关键理解总结（非常重要） <a class="header-anchor" href="#六、关键理解总结-非常重要" aria-label="Permalink to “六、关键理解总结（非常重要）”">​</a></h1><h3 id="_1-ip-地址本质" tabindex="-1">1. IP 地址本质 <a class="header-anchor" href="#_1-ip-地址本质" aria-label="Permalink to “1. IP 地址本质”">​</a></h3><p>👉 是“网络位置 + 设备编号”的组合</p><hr><h3 id="_2-网络层核心职责" tabindex="-1">2. 网络层核心职责 <a class="header-anchor" href="#_2-网络层核心职责" aria-label="Permalink to “2. 网络层核心职责”">​</a></h3><ul><li>跨网络寻址（IP）</li><li>路由选择（Router）</li></ul><hr><h3 id="_3-数据链路层-vs-网络层分工" tabindex="-1">3. 数据链路层 vs 网络层分工 <a class="header-anchor" href="#_3-数据链路层-vs-网络层分工" aria-label="Permalink to “3. 数据链路层 vs 网络层分工”">​</a></h3><table tabindex="0"><thead><tr><th>层级</th><th>作用</th></tr></thead><tbody><tr><td>数据链路层（MAC）</td><td>局域网内传输</td></tr><tr><td>网络层（IP）</td><td>跨网络传输</td></tr></tbody></table><hr><h1 id="七、一句话总结-考试用" tabindex="-1">七、一句话总结（考试用） <a class="header-anchor" href="#七、一句话总结-考试用" aria-label="Permalink to “七、一句话总结（考试用）”">​</a></h1><p>IP 地址是用于在网络层标识主机或路由器接口的逻辑地址，由网络号和主机号组成，用于实现跨网络通信与路由选择。</p>',73)])])}const P=i(t,[["render",h]]);export{p as __pageData,P as default};
